// --- Aggregation (Steering → Node 2) ---
const items = $input.all().map(i => i.json).filter(Boolean);
if (items.length === 0) {
  return [{ json: { skip: true, reason: 'Son 7 günde kayıt yok' } }];
}

const byCat = {};
let total = 0;
let night = 0;   // 22:00 - 06:00
let weekend = 0; // Cumartesi(6) - Pazar(7)

for (const it of items) {
  const cat = it.ai_category || 'Diğer';
  byCat[cat] = (byCat[cat] || 0) + parseFloat(it.price);
  total += parseFloat(it.price);
  const h = parseInt(it.hour_of_day, 10);
  if (h >= 22 || h < 6) night += parseFloat(it.price);
  if (it.day_of_week === 6 || it.day_of_week === 7) weekend += parseFloat(it.price);
}

const topCategory = Object.entries(byCat).sort((a, b) => b[1] - a[1])[0];

return [{
  json: {
    user_id: $('Kullanıcı Listesi').item.json.user_id,
    total,
    count: items.length,
    top_category: topCategory ? topCategory[0] : null,
    top_category_total: topCategory ? topCategory[1] : 0,
    night_total: night,
    weekend_total: weekend,
    by_category: byCat,
    period: 'son_7_gun'
  }
}];

// LLM metnini DB'ye yazacak payload hazırla.
return [{
  json: {
    user_id: $('Veri Agregasyonu').item.json.user_id,
    insight_text: ($input.first().json.content || '').toString().trim(),
    amount: $('Veri Agregasyonu').item.json.total,
    generated_at: new Date().toISOString()
  }
}];

// Steering → Node 5: opsiyonel push notification tetikleme noktası.
// Telegram/WhatsApp API entegrasyonu buraya eklenebilir.
console.log('İçgörü üretildi ve kaydedildi:', $json.insight_text);
return [{ json: { done: true } }];

// Veri yoksa sessizce atla.
console.log('Skip:', $json.reason);
return [{ json: { done: false, reason: $json.reason } }];
